  ('optometrist-moex-02989', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式隱形眼鏡驗配，以鏡片基弧8.00 mm，直徑9.4 mm，光學區8.0 mm，度數-3.00 DS之試戴片達理想 配戴，戴鏡驗光最佳視力20/20的度數為-5.00DS/-0.75DC×180，插片頂點距離13 mm，則此隱形眼鏡訂 片屈光度數最接近下列何者？', '["-5.00 DS", "-6.50 DS", "-8.00 DS", "-9.50 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f85cd30c1fda", "answer_pdf_sha1": "2c2bddf06560", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
