  ('optometrist-moex-02993', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '驗配老花隱形眼鏡時，瞳孔大小可以影響成功率。在相同光源及視物距離下，下列何種情況之瞳孔相對 較小？', '["40歲，-3.00 D", "40歲，+3.00 D", "50歲，-3.00 D", "50歲，+3.00 D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f85cd30c1fda", "answer_pdf_sha1": "2c2bddf06560", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
